<?php class Model_Mapper_Cuestionario{	private static $_instance;		public static function getInstance()	{		if(null == self::$_instance)		{			self::$_instance = new self;		}		return self::$_instance;	}	private function __construct(){}	public function getCuestionarios()	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()->from('tbl_cuestionario'));	}		public function getCuestionario($idCuestionario)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from('tbl_cuestionario')											->where('id_cuestionario = ?',$idCuestionario));	}		public function nuevoCuestionario($idUsuario,$estatus,$idEncuesta,$idIndicadorCabeza,$idIndicadorCola)	{		$fila = array(						'estatus_cuestionario' => $estatus,						'tbl_usuario_id_usuario' => $idUsuario,						'tbl_indicador_id_indicador_cola' => $idIndicadorCola,						'tbl_indicador_id_indicador_ultimo' => $idIndicadorCabeza,						'tbl_encuesta_id_encuesta' => $idEncuesta);			$db = Zend_Db_Table::getDefaultAdapter();		return $db->insert('tbl_cuestionario',$fila);			}		public function getEstatus($idCuestionario)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from(('tbl_cuestionario'),'estatus_cuestionario')											->where('id_cuestionario = ?',$idCuestionario));	}		public function setEstatus($idCuestionario,$estatus)	{		$fila = array(							'estatus_cuestionario' => $estatus,						'id_cuestionario' => $idCuestionario);		$db = Zend_Db_Table::getDefaultAdapter();		return $db->update('tbl_cuestionario',$fila,$db->quoteInto('id_cuestionario=?',$fila['id_cuestionario']));	}		public function getCuestionariosByUsuario($idUsuario)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchAll($db->select()	->from('tbl_cuestionario')											->where('tbl_usuario_id_usuario = ?',$idUsuario));	}		public function getCuestionariosTerminadosByUsuario($idUsuario)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchAll($db->select()	->from('tbl_cuestionario')											->where('tbl_usuario_id_usuario = ?',$idUsuario)											->where('estatus_cuestionario = "terminado"'));	}		public function updateUltimo($idCuestionario,$idIndicador)	{		$fila = array(							'tbl_indicador_id_indicador_ultimo' => $idIndicador,						'id_cuestionario' => $idCuestionario);		$db = Zend_Db_Table::getDefaultAdapter();		return $db->update('tbl_cuestionario',$fila,$db->quoteInto('id_cuestionario=?',$fila['id_cuestionario']));	}		public function getUltimoIndicador($idCuestionario)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from(('tbl_cuestionario'),'tbl_indicador_id_indicador_ultimo')											->where('id_cuestionario = ?',$idCuestionario));	}		public function getCola($idCuestionario)	{		$db = Zend_Db_Table::getDefaultAdapter();		$cuestionario = $db->fetchRow($db->select()	->from(('tbl_cuestionario'),'tbl_indicador_id_indicador_cola')											->where('id_cuestionario = ?',$idCuestionario));		return $cuestionario['tbl_indicador_id_indicador_cola'];	}		public function contarCuestionarios()	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchAll($db->select()	->from(("tbl_cuestionario"),array("estatus"=>"estatus_cuestionario","cant"=>"COUNT(id_cuestionario)"))											->group("estatus_cuestionario"));	}		public function contarCuestionariosByUsuario($idUsuario)	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchRow($db->select()	->from(("tbl_cuestionario"),array("cant"=>"COUNT(id_cuestionario)"))											->where('tbl_usuario_id_usuario = ?',$idUsuario));	}		public function contarCuestionariosByMes()	{		$db = Zend_Db_Table::getDefaultAdapter();		return $db->fetchAll($db->select()->from(array("c"=>"tbl_cuestionario"),array("mes"=>"DATE_FORMAT(c.fecha_cuestionario,'%Y-%m')","cant"=>"COUNT(c.id_cuestionario)"))											->group("DATE_FORMAT(c.fecha_cuestionario,'%Y-%m')"));	}}